import { Info } from "lucide-react";

import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";

export const title = "Info Box Outline";

const Example = () => (
  <Collapsible className="w-full max-w-lg rounded-lg border-2 border-blue-200 bg-blue-50 dark:border-blue-900 dark:bg-blue-950">
    <CollapsibleTrigger className="flex w-full items-center gap-3 p-4">
      <Info className="h-5 w-5 text-blue-600 dark:text-blue-400" />
      <span className="font-medium text-blue-900 dark:text-blue-100">
        Important Notice
      </span>
    </CollapsibleTrigger>
    <CollapsibleContent className="border-t-2 border-blue-200 px-4 py-3 text-sm text-blue-800 dark:border-blue-900 dark:text-blue-200">
      This is an informational message that provides additional context and
      details when expanded.
    </CollapsibleContent>
  </Collapsible>
);

export default Example;

import * as CollapsiblePrimitive from "@radix-ui/react-collapsible"

function Collapsible({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.Root>) {
  return <CollapsiblePrimitive.Root data-slot="collapsible" {...props} />
}

function CollapsibleTrigger({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.CollapsibleTrigger>) {
  return (
    <CollapsiblePrimitive.CollapsibleTrigger
      data-slot="collapsible-trigger"
      {...props}
    />
  )
}

function CollapsibleContent({
  ...props
}: React.ComponentProps<typeof CollapsiblePrimitive.CollapsibleContent>) {
  return (
    <CollapsiblePrimitive.CollapsibleContent
      data-slot="collapsible-content"
      {...props}
    />
  )
}

export { Collapsible, CollapsibleTrigger, CollapsibleContent }
